// ---------- ДАННЫЕ ----------

// Массив постов в памяти (пока без сервера)
let posts = [];
let nextPostId = 1;

// массив временных меток последних публикаций (в миллисекундах)
let postTimestamps = [];

// ---------- УТИЛИТЫ ----------

function createPostObject(text, imageUrl) {
  return {
    id: nextPostId++,
    username: "Гость",
    handle: "@guest",
    text,
    imageUrl: imageUrl || null,
    likes: 0,
    liked: false,
    createdAt: Date.now()
  };
}

// Сортировка: сначала по лайкам (убывание), затем по времени (новее выше)
function sortPosts() {
  posts.sort((a, b) => {
    if (b.likes !== a.likes) {
      return b.likes - a.likes;
    }
    return b.createdAt - a.createdAt;
  });
}

// ---------- РЕНДЕРИНГ ПОСТОВ ----------

const postsListEl = document.getElementById("posts-list");

function renderPosts() {
  postsListEl.innerHTML = "";

  sortPosts();

  posts.forEach((post) => {
    const li = document.createElement("li");
    li.className = "post";
    li.dataset.id = post.id;

    // Аватар
    const avatar = document.createElement("div");
    avatar.className = "post-avatar";

    // Контент поста
    const content = document.createElement("div");
    content.className = "post-content";

    // Верхняя часть (имя + хэндл)
    const header = document.createElement("div");
    header.className = "post-header";

    const username = document.createElement("span");
    username.className = "post-username";
    username.textContent = post.username;

    const handle = document.createElement("span");
    handle.className = "post-handle";
    handle.textContent = post.handle;

    header.appendChild(username);
    header.appendChild(handle);

    // Текст поста
    const text = document.createElement("div");
    text.className = "post-text";
    text.textContent = post.text;

    content.appendChild(header);
    content.appendChild(text);

    // Фото, если есть
    if (post.imageUrl) {
      const imageWrapper = document.createElement("div");
      imageWrapper.className = "post-image-wrapper";

      const img = document.createElement("img");
      img.className = "post-image";
      img.src = post.imageUrl;
      img.alt = "Изображение поста";

      imageWrapper.appendChild(img);
      content.appendChild(imageWrapper);
    }

    // Нижняя панель (лайки + комментарии)
    const footer = document.createElement("div");
    footer.className = "post-footer";

    // Кнопка лайка
    const likeButton = document.createElement("button");
    likeButton.className = "like-button";

    const likeIcon = document.createElement("img");
    likeIcon.className = "like-icon";
    likeIcon.src = post.liked ? "menu-icons/like1.svg" : "menu-icons/like.svg";
    likeIcon.alt = "Лайк";

    const likeCount = document.createElement("span");
    likeCount.className = "like-count";
    likeCount.textContent = post.likes;

    likeButton.appendChild(likeIcon);
    likeButton.appendChild(likeCount);

    likeButton.addEventListener("click", () => {
      toggleLike(post.id);
    });

    // Кнопка комментариев
    const commentButton = document.createElement("button");
    commentButton.className = "comment-button";
    commentButton.type = "button";

    const commentIcon = document.createElement("img");
    commentIcon.className = "comment-icon";
    commentIcon.src = "menu-icons/comments.svg";
    commentIcon.alt = "Комментарии";

    commentButton.appendChild(commentIcon);

    // Пока без обработчика клика (меню не работает)

    footer.appendChild(likeButton);
    footer.appendChild(commentButton);
    content.appendChild(footer);

    li.appendChild(avatar);
    li.appendChild(content);
    postsListEl.appendChild(li);
  });
}

// ---------- ЛАЙКИ ----------

function toggleLike(postId) {
  const post = posts.find((p) => p.id === postId);
  if (!post) return;

  post.liked = !post.liked;
  post.likes = post.liked ? post.likes + 1 : Math.max(0, post.likes - 1);

  renderPosts();
}

// ---------- РАБОТА С ФОРМОЙ СОЗДАНИЯ ПОСТА ----------

const createPostForm = document.getElementById("create-post-form");
const postTextInput = document.getElementById("post-text");
const postImageInput = document.getElementById("post-image");

createPostForm.addEventListener("submit", (event) => {
  event.preventDefault();

  const text = postTextInput.value.trim();
  const errorEl = document.getElementById("post-error");
  const now = Date.now();

  // очищаем старые записи старше 60 секунд
  postTimestamps = postTimestamps.filter(ts => now - ts < 60_000);

  // если за последнюю минуту уже 2 поста — блокируем
  if (postTimestamps.length >= 2) {
    if (errorEl) {
      errorEl.style.display = "block";
      errorEl.textContent = "не спамь, погоди минуту";
    }
    return; // не публикуем пост
  }

  // если текст пустой — просто выходим (ошибку не показываем)
  if (!text) {
    return;
  }

  // лимит не превышен — можно публиковать
  if (errorEl) {
    errorEl.style.display = "none";
  }

  const file = postImageInput.files[0];

  // фиксируем время публикации
  postTimestamps.push(now);

  // Если нет картинки
  if (!file) {
    const newPost = createPostObject(text, null);
    posts.unshift(newPost);
    postTextInput.value = "";
    postImageInput.value = "";
    renderPosts();
    return;
  }

  // Если есть картинка, читаем ее как dataURL
  const reader = new FileReader();
  reader.onload = function (e) {
    const imageUrl = e.target.result;
    const newPost = createPostObject(text, imageUrl);
    posts.unshift(newPost);
    postTextInput.value = "";
    postImageInput.value = "";
    renderPosts();
  };
  reader.readAsDataURL(file);
});

// ---------- НАВИГАЦИЯ МЕЖДУ СТРАНИЦАМИ ----------

const navButtons = document.querySelectorAll(".nav-item");
const pages = document.querySelectorAll(".page");

// Карта всех иконок
const iconMap = {
  home: {
    default: "menu-icons/feed.svg",
    hover:   "menu-icons/feed1.svg",
    active:  "menu-icons/feed2.svg"
  },
  search: {
    default: "menu-icons/explore.svg",
    hover:   "menu-icons/explore1.svg",
    active:  "menu-icons/explore2.svg"
  },
  notifications: {
    default: "menu-icons/notifications.svg",
    hover:   "menu-icons/notifications1.svg",
    active:  "menu-icons/notifications2.svg"
  },
  account: {
    default: "menu-icons/user.svg",
    hover:   "menu-icons/user1.svg",
    active:  "menu-icons/user2.svg"
  }
};

navButtons.forEach((btn) => {
  const pageKey = btn.dataset.page;
  const img = btn.querySelector(".nav-icon");

  // Стартовая иконка — обычная для неактивных, активная для активных
  if (iconMap[pageKey] && img) {
    if (btn.classList.contains("nav-item-active")) {
      img.src = iconMap[pageKey].active;
    } else {
      img.src = iconMap[pageKey].default;
    }
  }

  // HOVER: только для неактивных кнопок и только на десктопе
  btn.addEventListener("mouseenter", () => {
    const key = btn.dataset.page;
    const imgEl = btn.querySelector(".nav-icon");

    // Проверяем, что это не мобильное устройство (ширина экрана > 640px)
    if (window.innerWidth > 640 && !btn.classList.contains("nav-item-active") && iconMap[key] && imgEl) {
      imgEl.src = iconMap[key].hover;   // *1.svg
    }
  });

  btn.addEventListener("mouseleave", () => {
    const key = btn.dataset.page;
    const imgEl = btn.querySelector(".nav-icon");

    // Проверяем, что это не мобильное устройство (ширина экрана > 640px)
    if (window.innerWidth > 640 && !btn.classList.contains("nav-item-active") && iconMap[key] && imgEl) {
      imgEl.src = iconMap[key].default; // обратно *.svg
    }
  });

  // КЛИК: меняем активную кнопку и показываем страницу
  btn.addEventListener("click", () => {
    const target = btn.dataset.page;

    // 1) Снять активность со всех и вернуть обычные иконки
    navButtons.forEach((b) => {
      b.classList.remove("nav-item-active");

      const key = b.dataset.page;
      const imgEl = b.querySelector(".nav-icon");

      if (iconMap[key] && imgEl) {
        imgEl.src = iconMap[key].default;
      }
    });

    // 2) Текущая кнопка становится активной — ставим *2.svg
    btn.classList.add("nav-item-active");
    if (iconMap[target] && img) {
      img.src = iconMap[target].active;
    }

    // 3) Переключаем страницы
    pages.forEach((page) => {
      page.hidden = !page.classList.contains(`page-${target}`);
    });
  });
});

// ---------- НАЧАЛЬНЫЕ ДАННЫЕ (опционально) ----------

// Пара тестовых постов, чтобы лента не была пустой при первой загрузке
posts = [
  createPostObject("Добро пожаловать в «тупо». Это первый тестовый пост без картинки."),
  createPostObject("А это пост с тестовой картинкой. Можно загрузить свою, когда будете писать пост.")
];

// Для примера добавим лайков, чтобы увидеть сортировку
posts[0].likes = 3;
posts[0].liked = false;
posts[1].likes = 5;
posts[1].liked = false;

// Рендерим ленту при загрузке
renderPosts();

// Обработчик изменения размера окна для обновления иконок при смене режима (десктоп/мобильный)
window.addEventListener("resize", () => {
  navButtons.forEach((btn) => {
    const key = btn.dataset.page;
    const imgEl = btn.querySelector(".nav-icon");

    if (iconMap[key] && imgEl) {
      if (btn.classList.contains("nav-item-active")) {
        // Для активных кнопок всегда ставим активную иконку
        imgEl.src = iconMap[key].active;
      } else {
        // Для неактивных ставим обычную иконку
        imgEl.src = iconMap[key].default;
      }
    }
  });
});
